// Determina la ubicación para la consulta del clima.
// Prioridad: 1) GPS guardado por el usuario, 2) Caption de la foto, 3) Santiago (fallback)
const msg = $('Telegram: Recibe Foto').item.json.message;
const chatId = msg.chat.id;
const caption = msg.caption;

const staticData = $getWorkflowStaticData('global');
const savedLoc = staticData[`loc_${chatId}`];

const apiKey = 'TU_OPENWEATHERMAP_KEY';
let url;

if (savedLoc) {
  url = `https://api.openweathermap.org/data/2.5/weather?lat=${savedLoc.lat}&lon=${savedLoc.lon}&appid=${apiKey}&units=metric&lang=es`;
} else if (caption && caption.trim()) {
  url = `https://api.openweathermap.org/data/2.5/weather?q=${encodeURIComponent(caption.trim())}&appid=${apiKey}&units=metric&lang=es`;
} else {
  url = `https://api.openweathermap.org/data/2.5/weather?q=Santiago&appid=${apiKey}&units=metric&lang=es`;
}

const weatherData = await $http.request({ method: 'GET', url });
return [{ json: weatherData }];

// Guarda la ubicación GPS del usuario en la memoria del workflow (staticData por chat_id)
// Si el mensaje no trae ubicación (ej: texto plano), responde con ayuda.
const msg = $input.item.json.message;
const chatId = msg.chat.id;

if (!msg.location) {
  return [{ json: {
    chatId,
    text: '🌿 FitoScanAI listo. Envíame una 📸 foto de una planta para diagnosticarla, o comparte tu 📍 ubicación para que el análisis use el clima real de tu zona.'
  } }];
}

const lat = msg.location.latitude;
const lon = msg.location.longitude;

const staticData = $getWorkflowStaticData('global');
staticData[`loc_${chatId}`] = { lat, lon };

return [{ json: {
  chatId,
  text: `📍 Ubicación guardada (${lat.toFixed(4)}, ${lon.toFixed(4)}). Ahora manda una foto de la planta y usaré el clima de tu zona.`
} }];
